(function () {
  function addStyle() { if (document.getElementById('gfr-style')) return; var s = document.createElement('style'); s.id = 'gfr-style'; s.textContent = '.gfr-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.gfr-row{display:flex;gap:10px;flex-wrap:wrap;align-items:end}.gfr-row select{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.gfr-out{margin-top:12px;display:grid;gap:10px}.gfr-step{padding:10px;border-left:4px solid #007bff;background:#e8f4fd;border-radius:8px;line-height:1.7}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.gfrMounted) return; host.dataset.gfrMounted = '1'; addStyle(); host.innerHTML = '<div class="gfr-wrap"><h4>🧬 Giải truy hồi bằng hàm sinh</h4><div class="gfr-row"><label>Loại truy hồi <select data-type><option value="fib">Fibonacci: a_n=a_{n-1}+a_{n-2}</option><option value="geom">Bậc 1: a_n=2a_{n-1}</option><option value="arith">Cộng dồn: a_n=a_{n-1}+1</option></select></label><button type="button" data-run>Giải bằng hàm sinh</button></div><div class="gfr-out"></div></div>'; var out = host.querySelector('.gfr-out'); function run() { var t = host.querySelector('[data-type]').value, steps; if (t === 'fib') steps = ['Đặt G(x)=ΣF_nx^n, F0=0,F1=1.', 'Cộng từ n≥2: G(x)-x = xG(x)+x²G(x).', 'Suy ra G(x)=x/(1-x-x²).', 'Phân thức từng phần theo φ=(1+√5)/2, ψ=(1-√5)/2.', 'Hệ số: F_n=(φ^n-ψ^n)/√5.']; else if (t === 'geom') steps = ['Đặt G(x)=Σa_nx^n, a0=1.', 'Từ a_n=2a_{n-1}: G(x)-1 = 2xG(x).', 'G(x)=1/(1-2x).', 'Khai triển: 1+2x+4x²+...', 'Hệ số: a_n=2^n.']; else steps = ['Đặt G(x)=Σa_nx^n, a0=0.', 'Từ a_n=a_{n-1}+1: G(x)=xG(x)+x/(1-x).', 'G(x)=x/(1-x)².', 'Vì 1/(1-x)²=Σ(n+1)x^n.', 'Hệ số: a_n=n.']; out.innerHTML = steps.map(function (x, i) { return '<div class="gfr-step"><strong>Bước ' + (i + 1) + ':</strong> ' + x + '</div>'; }).join(''); } host.querySelector('[data-run]').addEventListener('click', run); run(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="gf-recurrence-solver"]').forEach(mount); });
}());
